/* ================================================================
   CinematicBanner.css — Shared hero banner (matches About hero)
   Uses theme.css variables.
   ================================================================ */

.cb-hero {
  position: relative;
  height: var(--cb-height, 88vh);
  min-height: 540px;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  background: var(--bg-primary);
}

/* ── Parallax background ───────────────────────────────────── */
.cb-bg {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center;
  filter: brightness(0.35) saturate(1.25) contrast(1.05);
  z-index: 1;
  will-change: transform;
  display: block;
  transition: filter 0.4s ease;
}

[data-theme="light"] .cb-bg {
  filter: brightness(0.42) saturate(1.15);
}

/* ── Dark gradient overlay ─────────────────────────────────── */
.cb-overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(to bottom,
      rgba(8, 8, 9, 0.15) 0%,
      rgba(8, 8, 9, 0.55) 65%,
      rgba(8, 8, 9, 0.92) 100%);
  z-index: 2;
  transition: background 0.4s ease;
}

[data-theme="light"] .cb-overlay {
  background: linear-gradient(to bottom,
      rgba(18, 16, 10, 0.1) 0%,
      rgba(18, 16, 10, 0.48) 65%,
      rgba(18, 16, 10, 0.90) 100%);
}

/* ── Bottom vignette bleeds into next section ──────────────── */
.cb-vignette {
  position: absolute;
  bottom: -2px;
  left: 0;
  right: 0;
  height: 160px;
  background: linear-gradient(to bottom, transparent, var(--bg-primary));
  z-index: 3;
  pointer-events: none;
}

/* ── Corner brackets ───────────────────────────────────────── */
.cb-corner {
  position: absolute;
  width: 52px;
  height: 52px;
  z-index: 4;
  pointer-events: none;
}

.cb-corner--tl {
  top: 34px;
  left: 34px;
  border-top: 1px solid var(--border-gold);
  border-left: 1px solid var(--border-gold);
}

.cb-corner--br {
  bottom: 34px;
  right: 34px;
  border-bottom: 1px solid var(--border-gold);
  border-right: 1px solid var(--border-gold);
}

/* ── Container ─────────────────────────────────────────────── */
.cb-container {
  position: relative;
  z-index: 5;
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
}

/* ── Content ───────────────────────────────────────────────── */
.cb-content {
  text-align: center;
  max-width: 1;
  padding: 0 5%;
}

/* Badge pill */
.cb-badge {
  display: inline-flex;
  align-items: center;
  gap: 11px;
  color: var(--accent-primary);
  text-transform: uppercase;
  letter-spacing: 7px;
  font-size: 10.5px;
  font-weight: 600;
  margin-bottom: 30px;
  font-family: var(--f-body, 'DM Sans', sans-serif);
}

.cb-badge::before,
.cb-badge::after {
  content: '';
  display: block;
  width: 24px;
  height: 1px;
  background: var(--border-gold);
}

/* Main title */
.cb-title {
  font-family: var(--f-display, 'Playfair Display', serif);
  font-size: clamp(3.2rem, 7vw, 6.8rem);
  font-weight: 900;
  text-transform: uppercase;
  line-height: 1.03;
  letter-spacing: 3px;
  margin-bottom: 28px;
  background: linear-gradient(165deg,
      #ffffff 20%,
      rgba(255, 255, 255, 0.42) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Subtitle */
.cb-sub {
  font-family: var(--f-serif, 'Cormorant Garamond', serif);
  font-style: italic;
  font-size: 1.08rem;
  letter-spacing: 2px;
  line-height: 1.78;
  color: rgba(255, 255, 255, 0.65);
  max-width: 440px;
  margin: 0 auto 42px;
}

/* Ornamental divider */
.cb-ornament {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 18px;
}

.cb-orn-line {
  display: block;
  width: 72px;
  height: 1px;
  background: linear-gradient(to right, transparent, var(--accent-primary));
}

.cb-orn-line--r {
  background: linear-gradient(to left, transparent, var(--accent-primary));
}

.cb-orn-diamond {
  color: var(--accent-primary);
  font-size: 8px;
  text-shadow: 0 0 14px var(--accent-primary);
}

/* ── Scroll hint ───────────────────────────────────────────── */
.cb-scroll-hint {
  position: absolute;
  bottom: 42px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 6;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
}

.cb-scroll-line {
  display: block;
  width: 1px;
  height: 50px;
  background: linear-gradient(to bottom, var(--accent-primary), transparent);
  animation: cbScrollPulse 2s ease-in-out infinite;
}

@keyframes cbScrollPulse {
  0% {
    transform: scaleY(0);
    transform-origin: top;
    opacity: 0;
  }

  50% {
    transform: scaleY(1);
    transform-origin: top;
    opacity: 1;
  }

  100% {
    transform: scaleY(1);
    transform-origin: bottom;
    opacity: 0;
  }
}

.cb-scroll-label {
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 4px;
  color: rgba(255, 255, 255, 0.45);
  font-family: var(--f-body, sans-serif);
}

/* ── Responsive ────────────────────────────────────────────── */
@media (max-width: 768px) {
  .cb-hero {
    height: 68vh;
    min-height: 400px;
  }

  .cb-title {
    font-size: clamp(2.2rem, 9vw, 3.2rem);
  }

  .cb-corner {
    display: none;
  }

  .cb-scroll-hint {
    display: none;
  }
}

@media (max-width: 480px) {
  .cb-hero {
    height: 58vh;
    min-height: 340px;
  }

  .cb-sub {
    display: none;
  }
}
